class MessageMediaPaidMedia(TLObject):
    """TL type: messageMediaPaidMedia"""
    CONSTRUCTOR_ID = 0xa8852491
    SUBCLASS_OF_ID = 0x476cbe32

    def __init__(self, stars_amount: int, extended_media: List['TypeMessageExtendedMedia']):
        self.stars_amount = stars_amount
        self.extended_media = extended_media

    def to_dict(self):
        return {
            '_': 'MessageMediaPaidMedia',
            'stars_amount': self.stars_amount,
            'extended_media': self.extended_media,
        }

    def _bytes(self) -> bytes:
        import io
        buf = io.BytesIO()
        buf.write(struct.pack('<I', self.CONSTRUCTOR_ID))
        buf.write(struct.pack('<q', self.stars_amount))
        buf.write(struct.pack('<i', 0x1cb5c415))  # vector id
        buf.write(struct.pack('<i', len(self.extended_media)))
        for item in self.extended_media:
            buf.write(bytes(item))
        return buf.getvalue()

    @classmethod
    def from_reader(cls, reader):
        _args = {}
        _val_stars_amount = reader.read_long()
        _args['stars_amount'] = _val_stars_amount
        _vec_id = reader.read_int(signed=False)
        if _vec_id != 0x1cb5c415:
            raise RuntimeError(f'Expected vector but got 0x{_vec_id:08x}')
        _count_extended_media = reader.read_int(signed=False)  # BUG6 fix: unsigned count
        _list_extended_media = []
        for _ in range(_count_extended_media):
            _item_extended_media = reader.tgread_object()
            _list_extended_media.append(_item_extended_media)
        _args['extended_media'] = _list_extended_media
        return cls(**_args)


